INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-permanent'), 1, 'Is laser hair removal permanent?', 'Laser hair removal produces permanent hair reduction — 70–90% of treated hair does not regrow. Some dormant follicles reactivate over years (especially with hormonal change), so most patients return for a maintenance session every 12–24 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-permanent'), 2, 'How many sessions will I need?', 'Most Indian patients (Fitzpatrick III–V) need 6–8 sessions for face and 6–10 for body, spaced 4–6 weeks apart. Your dermatologist will tailor the count to your skin type, hair colour and hormonal baseline during the AI skin analysis.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-permanent'), 3, 'Does hair grow back after laser?', 'A small percentage can — either from follicles dormant during your session series, or reactivated by hormonal changes. That is why most patients book a single maintenance session every 12–24 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-permanent'), 4, 'Is it safe for Indian skin?', 'Yes, when performed by a dermatologist using the right wavelength. We use Nd:YAG 1064nm for all Indian skin types (III–VI), which is the safest pigment-aware wavelength.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'is-laser-hair-removal-permanent'), 5, 'Why is laser not permanent on grey hair?', 'Lasers target melanin — the pigment in hair. Grey hair has little to no melanin, so the laser energy has nothing to absorb. For grey hair we offer electrolysis referrals.');

-- ===== difference-between-prp-and-gfc-for-hair =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Difference between PRP and GFC for hair — which is right for you?',
  'difference-between-prp-and-gfc-for-hair',
  'PRP and GFC are often used interchangeably, but they are different treatments with different processing, different injection profiles, and different results. A dermatologist explains.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "If you have been researching hair loss treatments in India, you have almost certainly seen PRP and GFC advertised side-by-side — sometimes as if they are the same thing. They are not. Both use your own blood, both involve injections into the scalp, but the preparation, the concentration, the comfort level, and the results are all different. Here is what actually separates them.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What is PRP?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "PRP — Platelet-Rich Plasma — is your blood, drawn, spun once in a centrifuge, and then re-injected into the thinning scalp. The single-spin process separates the plasma and platelets from the red blood cells. The resulting solution is rich in platelets and a range of growth factors, but it also contains some remaining red cells and white cells. PRP has been used in dermatology and orthopaedics for over a decade and has a solid track record for early-stage hair thinning.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What is GFC?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "GFC — Growth Factor Concentrate — is also derived from your blood, but it is processed differently. Your blood is drawn and passed through a two-step process: an activator is added that releases the growth factors from the platelets, and then a second spin separates out a pure, clear growth factor concentrate without the red cells or other cellular debris. The result is a more concentrated, cleaner growth factor solution.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "How the two differ in practice", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Processing: PRP is a single-spin; GFC is a two-step activated preparation.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Appearance: PRP is amber to red-tinged; GFC is a clear straw-coloured concentrate.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Comfort: GFC injections tend to be less painful and produce less post-session soreness.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Results timeline: Many patients see faster visible improvement with GFC — typically by session 3 — compared to session 4–5 on PRP.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Cost: GFC is typically 20–40% more expensive per session than PRP.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Which is right for you?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For early Norwood 1–2 or Ludwig I hair thinning, both work well — the choice often comes down to cost and comfort. For more established thinning with visibly miniaturised follicles, our dermatologists tend to prefer GFC because the cleaner growth factor concentrate delivers more consistent regrowth signalling. For post-partum telogen effluvium (the 3–6 month post-baby shed), either is appropriate — the key is to start before the bald patches become entrenched.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What to expect from a session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A full PRP or GFC session takes 45–60 minutes at Uncover. Numbing cream first, blood draw, processing, then the actual injections into the scalp in a planned grid pattern. Downtime is minimal — mild redness and scalp tenderness for a day, no washing hair for 24 hours. A typical loading phase is 4–6 sessions, one every 3–4 weeks, followed by maintenance every 3–4 months.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every hair loss plan at Uncover begins with an AI scalp analysis that maps your density, follicle health, and loss pattern — the choice between PRP and GFC is then based on what your scalp actually needs, not a menu.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'PRP vs GFC for Hair — Difference, Cost, Which Is Better | Uncover',
  'PRP and GFC both use your own blood to treat hair loss — but they are different. A dermatologist explains the difference, cost, and which works better for your hair loss pattern.',
  215,
  false,
  'published',
  now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair');

-- Clear then reinsert structured FAQs for re-runnability
