INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair'), 1, 'Is GFC better than PRP for hair?', 'For established thinning or patients where a cleaner, higher concentration of growth factors is appropriate, GFC often produces faster, more consistent results. For early-stage thinning, both are effective; PRP is a more budget-friendly option.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair'), 2, 'How much does GFC cost in Delhi?', 'GFC at Uncover starts from ₹5,399 per session. Most patients do 4–6 sessions in the loading phase, then one every 3–4 months for maintenance. Your dermatologist will share an itemised plan at consultation.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair'), 3, 'How many sessions of PRP or GFC will I need?', 'The typical loading phase is 4–6 sessions, one every 3–4 weeks. After that, maintenance sessions once every 3–4 months keep the density stable.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair'), 4, 'Can I combine PRP or GFC with minoxidil?', 'Yes — many protocols combine injectable growth factors with topical minoxidil and, where indicated, oral medication. This combined approach outperforms any single treatment for moderate hair loss.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'difference-between-prp-and-gfc-for-hair'), 5, 'Is PRP or GFC painful?', 'Mild discomfort is normal — we use numbing cream before the session. GFC tends to be less uncomfortable than PRP because the concentrate is cleaner. Soreness resolves within 24 hours.');

-- ===== how-to-stop-hair-fall-immediately =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'How to stop hair fall immediately — a dermatologist''s 4-week protocol',
  'how-to-stop-hair-fall-immediately',
  'There is no overnight fix for hair fall — but there is a structured 4-week protocol that controls the trigger, stops ongoing shed, and sets the stage for regrowth. Here is what dermatologists actually prescribe.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Every dermatologist hears \"how do I stop my hair fall immediately?\" multiple times a day. The honest answer is that there is no overnight cure — but a well-structured 4-week protocol can reduce active shedding by 40–60% and set the foundation for real regrowth over the following 3–6 months. Here is the protocol we actually use in the clinic.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Week 1 — Identify the trigger", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Hair fall has more than one cause, and treating it without knowing the trigger is a guaranteed waste of time. In week 1 your dermatologist will rule out or confirm the common triggers: iron or vitamin D deficiency (order a CBC + ferritin + vitamin D), thyroid dysfunction (TSH, T3, T4), hormonal (especially PCOS in women), post-illness or post-COVID telogen effluvium, crash-diet rebound, and traction from tight hairstyles. At Uncover this starts with an AI scalp analysis that maps density per zone so we can quantify before/after.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Week 2 — Start the three-pillar protocol", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Once the trigger is identified, we start the protocol on three fronts simultaneously:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Topical: a daily scalp serum with minoxidil (strength depends on sex and tolerance)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Nutritional: address any deficiencies with prescription supplements; not supermarket multivitamins", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "In-clinic: GFC, PRP, or mesotherapy start in week 2 to stimulate follicles directly", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Week 3 — Control lifestyle triggers", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "This is where most patients sabotage themselves. Tight hairstyles, chemical treatments, hot styling tools, and harsh shampoos prolong the shed regardless of what else you do. Switch to a sulphate-free shampoo, stop heat styling, avoid tight buns and braids, and ideally pause any coloring or straightening during the protocol.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Week 4 — First review", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "By week 4 the active shed should have noticeably slowed — most patients report fewer hairs in the shower drain and on the pillow. We do a second AI scalp scan to compare density per zone and adjust the protocol. If the shed is not slowing, we look for additional causes (autoimmune, scarring alopecia) and escalate as needed.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What to expect by month 3 and 6", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "By month 3, miniaturised follicles on the frontal and crown zones start thickening. By month 6, visible density improvement is measurable on imaging and often visible in photos. The key is compliance — hair is grown over quarters, not weeks.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A final note — if you are dealing with sudden, aggressive, or patchy hair loss, do not wait 4 weeks. See a dermatologist the same week. Conditions like alopecia areata respond best when treated within days of onset.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How to Stop Hair Fall Immediately — 4-Week Protocol | Uncover',
  'A dermatologist''s 4-week protocol to stop hair fall immediately — identify the cause, control the shed, and start regrowth. What actually works for Indian hair.',
  215,
  false,
  'published',
  now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately');

-- Clear then reinsert structured FAQs for re-runnability
DELETE FROM cms.blog_posts_structured_faqs
