INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately'), 1, 'What stops hair fall immediately at home?', 'Short-term: stop heat styling, switch to sulphate-free shampoo, avoid tight hairstyles, and address any iron/vitamin D deficiency with dermatologist-prescribed supplements. These alone slow the shed within 2–4 weeks; for real regrowth, add a dermatologist-supervised topical and in-clinic protocol.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately'), 2, 'Can stress-related hair fall be reversed?', 'Yes. Stress-induced telogen effluvium is self-limiting for most people — the shed stops 3–4 months after the trigger. A dermatologist-led plan (GFC or PRP plus topical) accelerates regrowth by 2–3 months versus waiting it out.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately'), 3, 'How quickly can a dermatologist stop hair fall?', 'Most patients see a noticeable reduction in active shed within 4 weeks on a three-pillar protocol (topical + nutrition + in-clinic therapy). Visible regrowth takes 3–6 months.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately'), 4, 'Do supplements really help hair fall?', 'Only if there is an underlying deficiency (iron, vitamin D, B12, zinc). Otherwise supplements do very little. Always get a blood test before starting any supplement protocol — over-supplementation has its own risks.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-to-stop-hair-fall-immediately'), 5, 'Is hair transplant the answer to hair fall?', 'No — transplants restore lost density, they do not stop ongoing fall. Any patient with active shedding needs the shed controlled first. Transplants are indicated only for stabilised, advanced hair loss where medical therapy cannot deliver the density you want.');

-- ===== can-laser-remove-tan-permanently =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'Can laser remove tan permanently? A dermatologist''s answer',
  'can-laser-remove-tan-permanently',
  'Laser toning is the fastest medical way to reverse a tan — but "permanent" depends on what you do after. A dermatologist explains what laser tan removal can and cannot do for Indian skin.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Laser toning is the most effective medical option to reverse tanning on Indian skin — but whether the result is truly permanent depends entirely on what you do afterwards. Here is the honest dermatologist answer to the most-asked tan-removal question in India.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What laser actually does to tan", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A Q-switched Nd:YAG laser — the standard safe-for-Indian-skin tan removal laser — emits very short, targeted pulses of light at 1064nm. That wavelength is absorbed by melanin without heating the surrounding skin. The laser fragments the excess melanin (tan pigment) into microscopic particles that your body then clears over 1–2 weeks through the lymphatic system. The tan is removed permanently in the sense that the current pigment is gone.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why your tan can come back", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Here is where \"permanent\" gets complicated. Your skin still has the same melanin-producing cells (melanocytes). If you go back to unprotected sun exposure — beach days, outdoor sports, commuting without sunscreen — those melanocytes will produce new melanin and your skin will tan again. Laser removes the pigment deposit; it does not change your skin''s response to UV.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "How many sessions do most patients need?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "For light-to-moderate tanning, most Indian patients (Fitzpatrick III–V) see visible results after 2 sessions and full clearance in 4–6 sessions, spaced 2–3 weeks apart. Deep, long-standing tans — athletes, frequent outdoor exposure, brides preparing for a wedding — may need 6–8 sessions. The plan is scaled to the depth of your tan, mapped during the AI skin analysis.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The non-negotiable part — your SPF protocol", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Without a strict SPF protocol, any laser-toning result will fade inside 3–6 months. What \"strict\" actually means:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "SPF 50 broad-spectrum sunscreen, every morning, 365 days a year", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Reapplication every 2 hours if outdoors", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Physical protection — hat, sunglasses, full-sleeve clothing for peak-sun exposure", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Tinted sunscreen with iron oxide (protects against visible light, which is a major trigger for melasma on Indian skin)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Avoid midday outdoor commuting where possible", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "What about melasma versus tan?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A common misunderstanding — pigmentation on Indian skin is often not just tan. Melasma, PIH (post-inflammatory hyperpigmentation), and sun spots are all pigment conditions but need different protocols. Laser toning alone can sometimes worsen melasma in susceptible patients. At Uncover we always diagnose with an AI skin analysis before recommending a laser-only plan versus a combination protocol with medical peels or topical prescriptions.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "The honest conclusion", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Yes, laser can remove your current tan permanently. No, it cannot prevent a new tan if you go back to unprotected sun. The patients who keep their results for years are the ones who pair 4–6 laser toning sessions with a lifelong SPF 50 routine. Everyone else tans again.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'Can Laser Remove Tan Permanently? Dermatologist Answer | Uncover',
  'Laser toning is the fastest medical way to remove tan for Indian skin. A dermatologist explains what laser tan removal can do, what it cannot, and why a sunscreen protocol is non-negotiable.',
  216,
  false,
  'published',
  now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently');

-- Clear then reinsert structured FAQs for re-runnability
DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently'), 1, 'Can laser remove tan permanently?', 'Laser removes the current tan permanently — but if you return to unprotected sun exposure, your skin will tan again. The pattern that lasts is laser toning plus a daily SPF 50 protocol.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently'), 2, 'Is laser tan removal safe for Indian skin?', 'Yes, when performed by a dermatologist using Q-switched Nd:YAG 1064nm. That wavelength is the safest for pigmented Indian skin. We do a test spot first for Fitzpatrick V and VI patients.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently'), 3, 'How many laser sessions for tan removal?', 'Most patients clear their tan in 4–6 sessions, spaced 2–3 weeks apart. Deeper, long-standing tans may need 6–8. Your dermatologist maps the plan after the AI skin analysis.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently'), 4, 'What is the difference between tan and melasma?', 'Tan is an even, UV-response darkening of the whole exposed area. Melasma is symmetrical, patchy, and often hormonal. PIH is localised darkening after an injury or acne. Each responds to a different protocol — diagnosis matters.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'can-laser-remove-tan-permanently'), 5, 'How much does laser tan removal cost in Delhi?', 'Laser toning at Uncover starts from ₹7,999 per session. Full packages are priced after consultation and the AI skin analysis.');

-- ===== how-long-does-botox-last =====
INSERT INTO cms.blog_posts (
  name, slug, excerpt, post_body,
  meta_title, meta_description,
  relationships_blog_post_category_id,
  featured, _status, published_at, created_at, updated_at
)
SELECT
  'How long does botox last? A dermatologist''s guide by treatment area',
  'how-long-does-botox-last',
  'Botox does not last the same in every area of the face. A dermatologist explains what to expect for forehead lines, crow''s feet, jawline slimming, and why consistent patients need fewer units over time.',
  '{"root": {"type": "root", "format": "", "indent": 0, "version": 1, "children": [{"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "How long botox lasts depends on where it is injected, how much is used, and what you do between sessions. The common answer of \"3 to 6 months\" is true on average — but the honest version is more nuanced, and knowing the nuance helps you plan your sessions better.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "By treatment area — what to expect", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Forehead lines — 3 to 4 months on average", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Glabella (frown / \"11\" lines) — 3 to 4 months", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Crow''s feet (around the eyes) — 3 to 4 months, often on the shorter end", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Bunny lines (bridge of nose) — 3 to 4 months", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Jawline slimming / masseter — 5 to 6 months (muscle is bigger, retrains slower)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 6, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Lip flip — 2 to 3 months (small dose, thin muscle)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 7, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Platysmal bands (neck) — 3 to 4 months", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Why duration varies between patients", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Botox acts on the neuromuscular junction — the signal between nerve and muscle. Over 3–6 months the body grows new nerve endings and the muscle regains full movement. How fast this happens varies:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Metabolism — faster metabolisms clear botox faster (athletes often report shorter duration)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Muscle mass — stronger, larger muscles (jawline, forehead) tend to keep botox working longer", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Repeat treatments — consistent patients need fewer units over time as muscles learn to relax", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Product used — different botulinum toxin brands have slightly different profiles; your dermatologist will pick based on area", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Dose — higher doses last slightly longer (but cause over-frozen results if overdone)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "How to make it last longer", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "A few evidence-backed habits extend results:", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "list", "tag": "ul", "start": 1, "listType": "bullet", "format": "", "indent": 0, "version": 1, "direction": "ltr", "children": [{"type": "listitem", "value": 1, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stay consistent — after 12–18 months of regular treatment, most patients need fewer units per session", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 2, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Use zinc + phytase supplements for 4 days before treatment (some studies show 20–30% longer duration)", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 3, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Avoid vigorous facial massage or sauna for 72 hours after injection", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 4, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Skip intense workouts for 24 hours post-treatment", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "listitem", "value": 5, "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Stay on the recommended top-up schedule — waiting 6+ months between sessions resets the muscle back to baseline", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}]}, {"type": "heading", "tag": "h2", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "When should you book your top-up?", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr"}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "Most dermatologists recommend booking your next session at the first sign of movement returning — usually around 3 months for face, 4–5 months for jawline. If you wait until the result is fully gone, you lose the compounding benefit of consistent treatment, and you need more units next time to catch up.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}, {"type": "paragraph", "format": "", "indent": 0, "version": 1, "children": [{"mode": "normal", "text": "At Uncover every botox plan starts with a facial muscle assessment — we map the muscles that drive your lines, plan dosing conservatively (under-treat first, add at review), and document with before/after photos. The philosophy is refresh, never alter.", "type": "text", "style": "", "detail": 0, "format": 0, "version": 1}], "direction": "ltr", "textFormat": 0, "textStyle": ""}], "direction": "ltr"}}'::jsonb,
  'How Long Does Botox Last? By Area, by Patient | Uncover',
  'Forehead, crow''s feet, jawline, masseter — botox lasts differently depending on area and patient. A dermatologist explains duration, top-up timing, and how to make results last longer.',
  216,
  false,
  'published',
  now(), now(), now()
WHERE NOT EXISTS (SELECT 1 FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last');

-- Clear then reinsert structured FAQs for re-runnability
DELETE FROM cms.blog_posts_structured_faqs
WHERE _parent_id = (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last');

INSERT INTO cms.blog_posts_structured_faqs (id, _parent_id, _order, question, answer)
VALUES
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last'), 1, 'How long does botox last on the forehead?', '3 to 4 months for most patients. After 12–18 months of consistent treatment, the forehead muscle retrains and most patients need fewer units and see slightly longer duration.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last'), 2, 'How long does jawline botox (masseter) last?', 'Usually 5 to 6 months — the masseter is a larger muscle so botox lasts longer in it. Most patients do two sessions a year for maintenance.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last'), 3, 'Can botox be permanent?', 'Not in a single session. But 12–18 months of consistent, correctly-dosed botox can produce a long-lasting softening of the treated muscle because the muscle learns to relax and the line engraves less deeply.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last'), 4, 'When should I book my botox top-up?', 'At the first sign of movement returning — usually 3 months for face, 4–5 months for jawline. Book before results are fully gone to keep the compounding benefit.'),
  (gen_random_uuid()::text, (SELECT id FROM cms.blog_posts WHERE slug = 'how-long-does-botox-last'), 5, 'How much does botox cost at Uncover?', 'Wrinkle relaxers start from ₹8,999 per area. Jawline botox and combined plans are priced after the consultation.');

COMMIT;
